if (! function_exists('dictionary_lookup')) {
    function dictionary_lookup($word, $language = null, $max_definitions = null, $timeout = null)
    {
        $word = trim($word ?? '');
        $language = $language ?? 'en';
        $timeout = (int)($timeout ?? 15);
        $max_definitions = (int)($max_definitions ?? 5);

        if (empty($word)) {
            return ['success' => false, 'error' => 'Word parameter is required.'];
        }
        if ($max_definitions < 1) $max_definitions = 1;
        if ($max_definitions > 20) $max_definitions = 20;

        // Free Dictionary API — no key, no rate limits
        $url = 'https://api.dictionaryapi.dev/api/v2/entries/' . urlencode($language) . '/' . urlencode(strtolower($word));

        $context = stream_context_create([
            'http' => [
                'method' => 'GET',
                'timeout' => $timeout,
                'header' => "User-Agent: self-bootstrapping-agent/1.0\r\nAccept: application/json\r\n",
                'ignore_errors' => true,
            ]
        ]);

        $response = @file_get_contents($url, false, $context);

        if ($response === false) {
            return ['success' => false, 'error' => 'Failed to reach dictionary API.'];
        }

        // Capture HTTP status
        $status_code = 200;
        if (isset($http_response_header)) {
            foreach ($http_response_header as $h) {
                if (preg_match('#HTTP/\d\.\d\s+(\d+)#', $h, $m)) {
                    $status_code = (int)$m[1];
                    break;
                }
            }
        }

        $data = json_decode($response, true);

        if ($data === null) {
            return ['success' => false, 'error' => 'Failed to parse API response.'];
        }

        // API returns 404 as a structured JSON object
        if ($status_code === 404 || (isset($data['title']) && $data['title'] === 'No Definitions Found')) {
            return [
                'success' => true,
                'word' => $word,
                'found' => false,
                'message' => $data['message'] ?? 'No definitions found for: ' . $word,
                'suggestions' => [],
                'definitions' => [],
            ];
        }

        if (!isset($data[0]['word'])) {
            return ['success' => false, 'error' => 'Unexpected API response format.', 'raw' => mb_substr($response, 0, 500)];
        }

        // Parse all entries
        $all_definitions = [];
        $all_phonetics = [];
        $all_synonyms = [];
        $all_antonyms = [];
        $all_examples = [];
        $sources = [];

        foreach ($data as $entry) {
            $entry_word = $entry['word'] ?? $word;
            
            // Phonetics
            if (isset($entry['phonetics'])) {
                foreach ($entry['phonetics'] as $ph) {
                    $phonetic = [
                        'text' => $ph['text'] ?? null,
                        'audio' => $ph['audio'] ?? null,
                    ];
                    if ($phonetic['text'] && !in_array($phonetic['text'], array_column($all_phonetics, 'text'))) {
                        $all_phonetics[] = $phonetic;
                    }
                }
            }
            
            // Phonetic text fallback
            if (isset($entry['phonetic']) && $entry['phonetic']) {
                $found = false;
                foreach ($all_phonetics as $ph) {
                    if ($ph['text'] === $entry['phonetic']) { $found = true; break; }
                }
                if (!$found) {
                    $all_phonetics[] = ['text' => $entry['phonetic'], 'audio' => null];
                }
            }
            
            // Meanings
            if (isset($entry['meanings'])) {
                foreach ($entry['meanings'] as $meaning) {
                    $pos = $meaning['partOfSpeech'] ?? 'unknown';
                    
                    foreach ($meaning['definitions'] as $def) {
                        if (count($all_definitions) >= $max_definitions) break 3;
                        
                        $d = [
                            'part_of_speech' => $pos,
                            'definition' => $def['definition'] ?? '',
                            'example' => $def['example'] ?? null,
                        ];
                        
                        if ($d['example']) {
                            $all_examples[] = $d['example'];
                        }
                        
                        // Synonyms
                        if (!empty($def['synonyms'])) {
                            foreach ($def['synonyms'] as $s) {
                                if (!in_array($s, $all_synonyms)) $all_synonyms[] = $s;
                            }
                        }
                        
                        // Antonyms
                        if (!empty($def['antonyms'])) {
                            foreach ($def['antonyms'] as $a) {
                                if (!in_array($a, $all_antonyms)) $all_antonyms[] = $a;
                            }
                        }
                        
                        $all_definitions[] = $d;
                    }
                    
                    // Meaning-level synonyms/antonyms
                    if (!empty($meaning['synonyms'])) {
                        foreach ($meaning['synonyms'] as $s) {
                            if (!in_array($s, $all_synonyms)) $all_synonyms[] = $s;
                        }
                    }
                    if (!empty($meaning['antonyms'])) {
                        foreach ($meaning['antonyms'] as $a) {
                            if (!in_array($a, $all_antonyms)) $all_antonyms[] = $a;
                        }
                    }
                }
            }
            
            // Source URLs
            if (isset($entry['sourceUrls'])) {
                foreach ($entry['sourceUrls'] as $s) {
                    $sources[] = $s;
                }
            }
        }

        // Build part-of-speech summary
        $pos_summary = [];
        foreach ($all_definitions as $d) {
            $p = $d['part_of_speech'];
            $pos_summary[$p] = ($pos_summary[$p] ?? 0) + 1;
        }

        return [
            'success' => true,
            'word' => $word,
            'found' => true,
            'phonetics' => $all_phonetics,
            'pronunciation' => $all_phonetics[0]['text'] ?? null,
            'audio_url' => $all_phonetics[0]['audio'] ?? null,
            'parts_of_speech' => array_keys($pos_summary),
            'definitions_count' => count($all_definitions),
            'definitions' => $all_definitions,
            'synonyms' => array_slice($all_synonyms, 0, 15),
            'antonyms' => array_slice($all_antonyms, 0, 10),
            'examples' => array_slice(array_unique($all_examples), 0, 5),
            'sources' => array_slice($sources, 0, 3),
        ];
    }
